func GetTenantUser(ctx context.Context, tenantID, userID string) (*User, error) {
    key := "user:" + userID  // no tenant prefix
    val, err := rdb.Get(ctx, key).Bytes()
    if err == redis.Nil {
        u, err := db.QueryUser(ctx, tenantID, userID)
        if err != nil {
            return nil, err
        }
        rdb.Set(ctx, key, marshal(u), 30*time.Minute)
        return u, nil
    }
    if err != nil {
        return nil, err
    }
    var u User
    json.Unmarshal(val, &u)
    return &u, nil
}
